func unconfiguredCount(d PageData) int {
	n := 0
	for _, st := range d.Integrations {
		if st.Required && !st.Configured {
			n++
		}
	}
	return n
}

func intToString(n int) string {
	if n == 0 {
		return "0"
	}
	if n > 99 {
		return "99+"
	}
	var b [12]byte
	i := len(b)
	for n > 0 {
		i--
		b[i] = byte('0' + n%10)
		n /= 10
	}
	return string(b[i:])
}

func activeClass(cur, key string) string {
	if cur == key {
		return "active"
	}
	return ""
}

